Write a stack using classes.
assistant
Certainly! Below is an example of how you can implement a simple stack using Python classes. This implementation includes basic stack operations such as `push`, `pop`, and `peek`.

```python
class Stack:
    def __init__(self):
        # Initialize an empty list to act as the stack
        self.items = []

    def is_empty(self):
        # Check if the stack is empty
        return len(self.items) == 0

    def push(self, item):
        # Add an item to the top of the stack
        self.items.append(item)

    def pop(self):
        # Remove and return the top item from the stack
        if not self.is_empty():
            return self.items.pop()
        else:
            raise IndexError("pop from an empty stack")

    def peek(self):
        # Return the top item from the stack without removing it
        if not self.is_empty():
            return self.items[-1]
        else:
            raise IndexError("peek from an empty stack")

    def size(self):
        # Return the number of items in the stack
        return len(self.items)

# Example usage:
if __name__ == "__main__":
    s = Stack()

    print("Is the stack empty?", s.is_empty())  # True

    s.push(1)
    s.push(2)
    s.push(3)

    print("Stack size:", s.size())  # 3

    print("Peek:", s.peek())

